def _resolve_dynamic_defaults(self, ctx: Context) -> None:
    """Resolve options whose ``default`` is a dynamic default mapping.

    Runs after every parameter has been parsed, so it can use the
    final values of the options it depends on. Only applies to
    options whose value came from :attr:`ParameterSource.DEFAULT`,
    i.e. no value was given on the command line, in an environment
    variable, or in ``default_map``.
    """
    params = self.get_params(ctx)
    opt_to_name = {
        opt: param.name
        for param in params
        if isinstance(param, Option)
        for opt in (*param.opts, *param.secondary_opts)
    }

    for param in params:
        if not isinstance(param, Option) or param._dynamic_default is None:
            continue

        if ctx.get_parameter_source(param.name) is not ParameterSource.DEFAULT:  # type: ignore[arg-type]
            continue

        resolved = None

        for source_opt, mapping in param._dynamic_default.items():
            source_name = opt_to_name.get(source_opt)

            if source_name is None or source_name not in ctx.params:
                continue

            key = str(ctx.params[source_name])

            if key in mapping:
                resolved = mapping[key]

        if resolved is not None:
            ctx.params[param.name] = resolved  # type: ignore[index]

